import React from "react";
import styles from "./quantity.module.css";

interface QuantityProps {
  classname?: string;
}

const Quantity: React.FC<QuantityProps> = ({ }) => {

  return (
    <div className={`${styles.wrapper_buttons} ${style}`}>
      <button className={styles.btn_quanity}> - </button>
      <span className={styles.count_quantity}>1</span>
      <button className={styles.btn_quanity}> + </button>
    </div>
  );
};

export default Quantity;
